-- Regenerate with: node scripts/generate-backend-truth.mjs
-- P0 hotfix: pin search_path on the v5 helper so pgcrypto.digest resolves
-- from any caller role.
--
-- The original _ai_chat_key_uuid_v5 function called `digest(...)` without
-- a schema qualifier. On modern Supabase pgcrypto lives in the
-- `extensions` schema, not `public`. When the function ran from PostgREST
-- under the `authenticated` role the default search_path was just
-- `public, pg_catalog`, so digest() failed to resolve and the call threw
--   ERROR: function digest(bytea, unknown) does not exist
-- The same call succeeded at apply-migration time because the migration
-- role has a wider search_path that includes `extensions`, which masked
-- the bug until the bot actually invoked resolve_ai_chat_key in an
-- authenticated session against ai-inference.
--
-- Fix: pin search_path on both _ai_chat_key_uuid_v5 and resolve_ai_chat_key
-- so they always find the pgcrypto entry point regardless of caller role.
-- The functions stay IMMUTABLE / parallel safe so the generated stored
-- column on project_ai_chat_sessions still qualifies (set search_path is
-- allowed on IMMUTABLE functions).
--
-- Reference: docs/rovno-bots-plan.md section 4.4, P1 smoke-test failure.

create or replace function public._ai_chat_key_uuid_v5(
  p_namespace uuid,
  p_name text
)
returns uuid
language plpgsql
immutable
parallel safe
set search_path = public, extensions, pg_catalog
as $$
declare
  ns_bytes bytea;
  hash     bytea;
  raw      bytea;
  hex_str  text;
begin
  ns_bytes := decode(replace(p_namespace::text, '-', ''), 'hex');
  hash     := digest(ns_bytes || convert_to(p_name, 'UTF8'), 'sha1');
  raw      := substring(hash from 1 for 16);

  raw := set_byte(raw, 6, (get_byte(raw, 6) & 15) | 80);
  raw := set_byte(raw, 8, (get_byte(raw, 8) & 63) | 128);

  hex_str := encode(raw, 'hex');
  return (
    substring(hex_str, 1, 8)  || '-' ||
    substring(hex_str, 9, 4)  || '-' ||
    substring(hex_str, 13, 4) || '-' ||
    substring(hex_str, 17, 4) || '-' ||
    substring(hex_str, 21, 12)
  )::uuid;
end;
$$;

revoke all on function public._ai_chat_key_uuid_v5(uuid, text) from public;
grant execute on function public._ai_chat_key_uuid_v5(uuid, text) to authenticated;

create or replace function public.resolve_ai_chat_key(
  p_profile_id uuid,
  p_project_id uuid
)
returns uuid
language sql
immutable
parallel safe
set search_path = public, extensions, pg_catalog
as $$
  select public._ai_chat_key_uuid_v5(
    public._ai_chat_key_namespace(),
    p_profile_id::text || ':' || p_project_id::text
  )
$$;

revoke all on function public.resolve_ai_chat_key(uuid, uuid) from public;
grant execute on function public.resolve_ai_chat_key(uuid, uuid) to authenticated;
